const { loadPreferences, savePreferences, ROCKET_TYPE_OPTIONS, LAUNCH_SITE_OPTIONS, ASTRO_EVENT_CATEGORIES } = require('../../../utils/user-growth.js')
const { getUiShellLayout } = require('../../../utils/layout.js')

function arrayToMap(arr) {
  var map = {}
  if (arr && arr.length) {
    for (var i = 0; i < arr.length; i++) {
      map[arr[i]] = true
    }
  }
  return map
}

Page({
  data: {
    statusBarHeight: 44,
    navPlaceholderHeight: 0,
    rocketOptions: ROCKET_TYPE_OPTIONS,
    siteOptions: LAUNCH_SITE_OPTIONS,
    astroOptions: ASTRO_EVENT_CATEGORIES,
    notifyOptions: [
      { value: 30, label: '30分钟前' },
      { value: 60, label: '1小时前' },
      { value: 120, label: '2小时前' }
    ],
    selectedRockets: [],
    selectedSites: [],
    selectedAstro: [],
    rocketMap: {},
    siteMap: {},
    astroMap: {},
    notifyMinutes: 60,
    briefingEnabled: true,
    saving: false
  },

  onLoad() {
    var layout = getUiShellLayout()
    this.setData({
      statusBarHeight: layout.statusBarHeight,
      navPlaceholderHeight: layout.navPlaceholderHeight
    })
    this._loadPrefs()
  },

  _loadPrefs() {
    var prefs = loadPreferences()
    var rockets = prefs.rocketTypes || []
    var sites = prefs.launchSites || []
    var astro = prefs.astroEventTypes || []
    this.setData({
      selectedRockets: rockets,
      selectedSites: sites,
      selectedAstro: astro,
      rocketMap: arrayToMap(rockets),
      siteMap: arrayToMap(sites),
      astroMap: arrayToMap(astro),
      notifyMinutes: prefs.notifyMinutes || 60,
      briefingEnabled: prefs.briefingEnabled !== false
    })
  },

  onToggleRocket(e) {
    var name = e.currentTarget.dataset.name
    var list = this.data.selectedRockets.slice()
    var map = Object.assign({}, this.data.rocketMap)
    var idx = list.indexOf(name)
    if (idx >= 0) {
      list.splice(idx, 1)
      delete map[name]
    } else {
      list.push(name)
      map[name] = true
    }
    this.setData({ selectedRockets: list, rocketMap: map })
  },

  onToggleSite(e) {
    var name = e.currentTarget.dataset.name
    var list = this.data.selectedSites.slice()
    var map = Object.assign({}, this.data.siteMap)
    var idx = list.indexOf(name)
    if (idx >= 0) {
      list.splice(idx, 1)
      delete map[name]
    } else {
      list.push(name)
      map[name] = true
    }
    this.setData({ selectedSites: list, siteMap: map })
  },

  onToggleAstro(e) {
    var id = e.currentTarget.dataset.id
    var list = this.data.selectedAstro.slice()
    var map = Object.assign({}, this.data.astroMap)
    var idx = list.indexOf(id)
    if (idx >= 0) {
      list.splice(idx, 1)
      delete map[id]
    } else {
      list.push(id)
      map[id] = true
    }
    this.setData({ selectedAstro: list, astroMap: map })
  },

  onNotifyChange(e) {
    this.setData({ notifyMinutes: Number(e.currentTarget.dataset.value) || 60 })
  },

  onBriefingToggle(e) {
    this.setData({ briefingEnabled: !!e.detail.value })
  },

  onSave() {
    if (this.data.saving) return
    this.setData({ saving: true })

    var prefs = {
      rocketTypes: this.data.selectedRockets,
      launchSites: this.data.selectedSites,
      astroEventTypes: this.data.selectedAstro,
      notifyMinutes: this.data.notifyMinutes,
      briefingEnabled: this.data.briefingEnabled
    }
    savePreferences(prefs)

    var self = this
    // 保存后请求订阅消息授权，确保后续自动匹配的提醒能发出去
    var tmplId = 'T5J5sRh2UdEwFE7q_VTbdowA0PeXrz_3bUweWEL6uBs'
    wx.requestSubscribeMessage({
      tmplIds: [tmplId],
      complete: function () {
        self.setData({ saving: false })
        wx.showToast({ title: '保存成功', icon: 'success' })
      }
    })
  },

  goBack() {
    wx.navigateBack({ delta: 1 })
  }
})
